-- tedw_release_summary
VALUES (
'
<span style="background-color: #9D0208; color: white; font-weight: bold; font-size: 18px; padding: 5px; display: inline-block; text-decoration: underline;">Release Summary - 03/10/2025 :</span>
<h4 style="margin-top: 0;">This release includes the following:</h4>
<ol>
    <li>Enhancements - 13
        <ul>
			<li>Snapsheet related enhancements : </li>
			1) Added automated data validation scripts to ensure data quality and to ensure that the data was successfully migrated.<br>
			2) Updated stored procedure logic to load policy_effective_dt in tclaim table for NFP policies.<br>
			3) Updated stored procedure logic to load payment_submitted_nm and payment_approver_nm in tclaim_payment table.<br>
			4) Updated stored procedure logic to load missing payee_nm in tclaim_payment table.<br>
			5) Updated stored procedure logic to load missing recovery payment into snapsheet financial transactions actions table.<br>
			6) Loaded missing coverage name and aslob into tclaim_feature and tclaim_feature_summary tables.<br>
			7) Updated stored procedure logic to remove extra spaces in region variable for policyEntities field in snapsheet policy search and policy webhook.<br>
			8) Created provisional policies to support litigation claims in Snapsheet.
			<li>EDW Enhancements : </li>
			1) Updated quote_status logic by capturing new quote close types and reasons in EDW for better reporting on lost business.  Also added competitor_carrier_nm and close_reason_other_desc to tquote table.<br>
			2) Updated quote_status related columns in summary table to reflect new quote close reasons. Refreshed quote_status related columns in trenewal_summary and tbroker_summary tables to reflect new quote close reasons. <br>
			3) Added transaction_status field to tpolicy_history table to capture reversed/reversal/issued transactions status.<br>
			4) Updated logic to load transaction reviewed/created user_sk in tquote_transaction and tpolicy_transaction.
			<li>Backfilled wildfire protection data using information gathered from manual forms for the Redzone feed. </li>
		</ul>
    </li>
    <li>Bug tickets - 13
        <ul>
			<li>Updated stored procedure logic to load missing extended_liability_location_ct in thome_additional_coverage table.</li>
			<li>Updated stored procedure logic to populate term_no in tpolicy table for cancelled rewrite policies.</li>
			<li>Rollback defense_reserve_amt for historic ebao transactions.</li>
			<li>Minor code changes applied to HSB inforce feed to make it production ready.</li>
			<li>Fixed a few home_cyber_protection_coverage_limit_amt and home_systems_protection_limit_amt by making them null where the indicator for these coverages were no but limit amounts were set. This is just a onetime datafix.</li>
			<li>Fixed wind_or_hailstorm_deductible data format issues for home policies. This is just a onetime datafix.</li>
			<li>Resolved 1 ticket associated with updating logic to send latest broker information in quotes and policy feed to hubspot.</li>
			<li>Resolved 1 ticket associated with updating BCEGCreditPercent for one policy.</li>
			<li>Resolved 1 ticket associated with updating CreatedDate and UpdatedDate for one record in user table</li>
			<li>Resolved 2 tickets associated with repushing of policies associated with data fixes applied on IVANS.</li>
			<li>Resolved 1 ticket associated with adding alerts to list of policies as per user request.</li>
			<li>Fixed missing users in tuser table. Fixed data in following downstream tables associated with this change. </li>
			1) tuser<br>
			2) tbroker_vault_team<br>
			3) tnote<br>
			4) tquote_note_hubspot_feed<br>
			5) tquote_status_history<br>
			6) tquote_transaction_status_history<br>
			7) tquote_history<br>
			8) tpolicy_history<br>
			9) ttask
		</ul>
    </li>
</ol>
'
,'Yes'
,'2025-03-10'
,getdate()
,getdate()
)
;

-- tedw_release_note
